5168 static bool canNarrowOps(ArrayRef<VPValue *> Ops) {
5169   SmallVector<VPValue *> Ops0;
5170   auto *WideMember0 = dyn_cast<VPSingleDefRecipe>(Ops[0]);
5171   if (!WideMember0)
5172     return false;
5173   for (VPValue *V : Ops) {
5174     if (!isa<VPWidenRecipe, VPWidenCastRecipe>(V))
5175       return false;
5176     auto *R = cast<VPSingleDefRecipe>(V);
5177     if (getOpcodeOrIntrinsicID(R) != getOpcodeOrIntrinsicID(WideMember0))
5178       return false;
5179   }
