5288   if (auto *RepR = dyn_cast<VPReplicateRecipe>(R)) {
5289     assert(RepR->isSingleScalar() &&
5290            isa<LoadInst>(RepR->getUnderlyingInstr()) &&
5291            "must be a single scalar load");
5292     NarrowedOps.insert(RepR);
5293     return RepR;
5294   }
